1	import { useState } from "react";
2	import { useEventTrade } from "@/lib/query/hooks";
3	import { useSession } from "@/features/session/context";
4	import type { Market, AssetDelta } from "@/lib/api/types";
5	
6	function TradeReceipt({ delta }: { delta: AssetDelta }) {
7	  const impact = delta.impactScore;
8	  const impactColor = impact > 0.5 ? "var(--color-danger)" : impact > 0.2 ? "var(--color-warning, orange)" : "var(--color-text-muted)";
9	
10	  return (
11	    <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "var(--space-sm)", marginTop: "var(--space-xs)", fontSize: "0.75rem" }}>
12	      <div>
13	        <div style={{ color: "var(--color-text-muted)" }}>Before</div>
14	        <div style={{ fontFamily: "var(--font-mono)" }}>{delta.beforeMinAsset.toFixed(2)}</div>
15	      </div>
16	      <div>
17	        <div style={{ color: "var(--color-text-muted)" }}>After</div>
18	        <div style={{ fontFamily: "var(--font-mono)" }}>{delta.afterMinAsset.toFixed(2)}</div>
19	      </div>
20	      <div>
21	        <div style={{ color: "var(--color-text-muted)" }}>Impact</div>
22	        <div style={{ fontFamily: "var(--font-mono)", color: impactColor }}>{(impact * 100).toFixed(1)}%</div>
23	      </div>
24	      <div>
25	        <div style={{ color: "var(--color-text-muted)" }}>Limit</div>
26	        <div style={{ fontFamily: "var(--font-mono)" }}>{delta.riskLimit.toFixed(2)}</div>
27	      </div>
28	    </div>
29	  );
30	}
31	
32	interface Props {
33	  market: Market;
34	}
35	
36	export function EventTradePanel({ market }: Props) {
37	  const { session, isConfigured } = useSession();
38	  const mutation = useEventTrade(market.id);
39	  const [selectedOutcome, setSelectedOutcome] = useState<string>("");
40	  const [side, setSide] = useState<"buy" | "sell">("buy");
41	
42	  if (market.status !== "active") return null;
43	  if (!isConfigured) return null;
44	
45	  const currentPrice = selectedOutcome ? (market.marginals[selectedOutcome] ?? 0) : 0;
46	
47	  const handleTrade = () => {
48	    if (!selectedOutcome) return;
49	
50	    mutation.mutate({
51	      payload: {
52	        accountId: session.accountId,
53	        formula: [[{
54	          variableId: market.id,
55	          outcomeId: selectedOutcome,
56	          negated: false,
57	        }]],
58	        side,
59	        idempotencyKey: crypto.randomUUID(),
60	      },
61	      session,
62	    });
63	  };
64	
65	  return (
66	    <div style={panelStyle}>
67	      <div style={{ fontSize: "0.85rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>
68	        Quick Trade
69	      </div>
70	
71	      <div style={{ display: "flex", gap: "var(--space-sm)", alignItems: "center", flexWrap: "wrap" }}>
72	        {/* Side toggle */}
73	        <div style={{ display: "flex", borderRadius: "var(--radius-sm)", overflow: "hidden", border: "1px solid var(--color-border)" }}>
74	          <button
75	            onClick={() => setSide("buy")}
76	            style={{
77	              ...sideBtnStyle,
78	              background: side === "buy" ? "var(--color-success, #22c55e)" : "transparent",
79	              color: side === "buy" ? "#fff" : "var(--color-text-muted)",
80	            }}
81	          >
82	            Buy
83	          </button>
84	          <button
85	            onClick={() => setSide("sell")}
86	            style={{
87	              ...sideBtnStyle,
88	              background: side === "sell" ? "var(--color-danger, #ef4444)" : "transparent",
89	              color: side === "sell" ? "#fff" : "var(--color-text-muted)",
90	            }}
91	          >
92	            Sell
93	          </button>
94	        </div>
95	
96	        {/* Outcome selector */}
97	        <select
98	          value={selectedOutcome}
99	          onChange={(e) => setSelectedOutcome(e.target.value)}
100	          style={selectStyle}
101	        >
102	          <option value="">Select outcome...</option>
103	          {market.outcomes.map((o) => (
104	            <option key={o.id} value={o.id}>
105	              {o.name} @ {((market.marginals[o.id] ?? 0) * 100).toFixed(1)}%
106	            </option>
107	          ))}
108	        </select>
109	
110	        {selectedOutcome && (
111	          <span style={{ fontSize: "0.8rem", color: "var(--color-text-muted)" }}>
112	            Price: {(currentPrice * 100).toFixed(1)}%
113	          </span>
114	        )}
115	
116	        <button
117	          onClick={handleTrade}
118	          disabled={!selectedOutcome || mutation.isPending}
119	          style={{
120	            ...tradeBtnStyle,
121	            background: side === "buy" ? "var(--color-success, #22c55e)" : "var(--color-danger, #ef4444)",
122	            opacity: selectedOutcome ? 1 : 0.5,
123	            cursor: selectedOutcome && !mutation.isPending ? "pointer" : "not-allowed",
124	          }}
125	        >
126	          {mutation.isPending
127	            ? "Submitting..."
128	            : `${side === "buy" ? "Buy" : "Sell"} ${selectedOutcome || "..."}`}
129	        </button>
130	      </div>
131	
132	      {mutation.isSuccess && (
133	        <div style={successStyle}>
134	          <div>Trade accepted — Order {mutation.data.order.orderId}</div>
135	          <TradeReceipt delta={mutation.data.assetDelta} />
136	        </div>
137	      )}
138	
139	      {mutation.isError && (
140	        <div style={errorStyle}>
141	          {mutation.error instanceof Error ? mutation.error.message : "Trade failed"}
142	        </div>
143	      )}
144	    </div>
145	  );
146	}
147	
148	const panelStyle: React.CSSProperties = {
149	  padding: "var(--space-md)",
150	  borderRadius: "var(--radius-md)",
151	  border: "1px solid var(--color-border)",
152	  background: "var(--color-bg-surface)",
153	};
154	
155	const sideBtnStyle: React.CSSProperties = {
156	  padding: "4px 14px",
157	  border: "none",
158	  fontSize: "0.8rem",
159	  fontWeight: 600,
160	  cursor: "pointer",
161	};
162	
163	const selectStyle: React.CSSProperties = {
164	  padding: "6px 12px",
165	  borderRadius: "var(--radius-sm)",
166	  border: "1px solid var(--color-border)",
167	  background: "var(--color-bg)",
168	  color: "var(--color-text)",
169	  fontSize: "0.85rem",
170	};
171	
172	const tradeBtnStyle: React.CSSProperties = {
173	  padding: "6px 16px",
174	  borderRadius: "var(--radius-sm)",
175	  border: "none",
176	  color: "#fff",
177	  fontWeight: 600,
178	  fontSize: "0.85rem",
179	};
180	
181	const successStyle: React.CSSProperties = {
182	  marginTop: "var(--space-sm)",
183	  padding: "var(--space-xs) var(--space-sm)",
184	  borderRadius: "var(--radius-sm)",
185	  background: "rgba(34, 197, 94, 0.1)",
186	  border: "1px solid var(--color-success, #22c55e)",
187	  fontSize: "0.8rem",
188	  color: "var(--color-success, #22c55e)",
189	};
190	
191	const errorStyle: React.CSSProperties = {
192	  marginTop: "var(--space-sm)",
193	  padding: "var(--space-xs) var(--space-sm)",
194	  borderRadius: "var(--radius-sm)",
195	  background: "rgba(239, 68, 68, 0.1)",
196	  border: "1px solid var(--color-danger)",
197	  fontSize: "0.8rem",
198	  color: "var(--color-danger)",
199	};
