1	import { describe, it, expect, vi, beforeEach } from "vitest";
2	import { screen, fireEvent } from "@testing-library/react";
3	import { renderWithProviders } from "./helpers";
4	import { TradingPanel } from "@/features/trading/TradingPanel";
5	import type { Market } from "@/lib/api/types";
6	
7	// ---------------------------------------------------------------------------
8	// Mocks
9	// ---------------------------------------------------------------------------
10	
11	const mockMutate = vi.fn();
12	
13	vi.mock("@/features/session/context", async () => {
14	  const actual = await vi.importActual<typeof import("@/features/session/context")>(
15	    "@/features/session/context",
16	  );
17	  return {
18	    ...actual,
19	    useSession: vi.fn(),
20	  };
21	});
22	
23	vi.mock("@/lib/query/hooks", () => ({
24	  useProbabilityEdit: vi.fn(),
25	}));
26	
27	import { useSession } from "@/features/session/context";
28	import { useProbabilityEdit } from "@/lib/query/hooks";
29	
30	const mockUseSession = vi.mocked(useSession);
31	const mockUseProbabilityEdit = vi.mocked(useProbabilityEdit);
32	
33	// ---------------------------------------------------------------------------
34	// Fixtures
35	// ---------------------------------------------------------------------------
36	
37	const mockMarket: Market = {
38	  id: "mkt-1",
39	  title: "Will it rain tomorrow?",
40	  description: "Rain forecast market",
41	  variableId: "var-1",
42	  status: "active",
43	  outcomes: [
44	    { id: "out-yes", name: "Yes" },
45	    { id: "out-no", name: "No" },
46	  ],
47	  marginals: { "out-yes": 0.65, "out-no": 0.35 },
48	  liquidity: 1000,
49	  volume: 500,
50	  created_at: "2026-01-01T00:00:00Z",
51	  expires_at: "2026-12-31T00:00:00Z",
52	};
53	
54	const configuredSession = {
55	  session: { accountId: "acc-123", agentId: "agent-1" },
56	  setAccountId: vi.fn(),
57	  setAgentId: vi.fn(),
58	  isConfigured: true,
59	};
60	
61	const unconfiguredSession = {
62	  session: { accountId: "", agentId: "" },
63	  setAccountId: vi.fn(),
64	  setAgentId: vi.fn(),
65	  isConfigured: false,
66	};
67	
68	function defaultMutationState(overrides: Record<string, unknown> = {}) {
69	  return {
70	    mutate: mockMutate,
71	    mutateAsync: vi.fn(),
72	    reset: vi.fn(),
73	    isPending: false,
74	    isSuccess: false,
75	    isError: false,
76	    isIdle: true,
77	    status: "idle" as const,
78	    data: undefined,
79	    error: null,
80	    variables: undefined,
81	    failureCount: 0,
82	    failureReason: null,
83	    submittedAt: 0,
84	    context: undefined,
85	    ...overrides,
86	  } as unknown as ReturnType<typeof useProbabilityEdit>;
87	}
88	
89	// ---------------------------------------------------------------------------
90	// Setup
91	// ---------------------------------------------------------------------------
92	
93	beforeEach(() => {
94	  vi.clearAllMocks();
95	  mockUseSession.mockReturnValue(configuredSession);
96	  mockUseProbabilityEdit.mockReturnValue(defaultMutationState());
97	});
98	
99	// ---------------------------------------------------------------------------
100	// Tests
101	// ---------------------------------------------------------------------------
102	
103	describe("TradingPanel", () => {
104	  it("shows setup message when session is not configured", () => {
105	    mockUseSession.mockReturnValue(unconfiguredSession);
106	    renderWithProviders(<TradingPanel market={mockMarket} />);
107	
108	    expect(screen.getByText(/Set your Account ID/)).toBeInTheDocument();
109	    expect(screen.queryByRole("form")).not.toBeInTheDocument();
110	  });
111	
112	  it("renders trading form when session is configured", () => {
113	    renderWithProviders(<TradingPanel market={mockMarket} />);
114	
115	    expect(screen.getByRole("heading", { name: "Probability Edit" })).toBeInTheDocument();
116	
117	    // Outcome select with options
118	    const select = screen.getByRole("combobox");
119	    expect(select).toBeInTheDocument();
120	    expect(screen.getByText("Yes (65.0%)")).toBeInTheDocument();
121	    expect(screen.getByText("No (35.0%)")).toBeInTheDocument();
122	
123	    // Slider
124	    expect(screen.getByRole("slider")).toBeInTheDocument();
125	
126	    // Submit button
127	    expect(screen.getByRole("button", { name: "Submit Edit" })).toBeInTheDocument();
128	  });
129	
130	  it("updates probability display when slider changes", () => {
131	    renderWithProviders(<TradingPanel market={mockMarket} />);
132	
133	    const slider = screen.getByRole("slider");
134	    fireEvent.change(slider, { target: { value: "0.75" } });
135	
136	    expect(screen.getByText(/75\.0%/)).toBeInTheDocument();
137	  });
138	
139	  it("calls mutation.mutate with correct payload on form submission", () => {
140	    renderWithProviders(<TradingPanel market={mockMarket} />);
141	
142	    // Change outcome to second option
143	    const select = screen.getByRole("combobox");
144	    fireEvent.change(select, { target: { value: "out-no" } });
145	
146	    // Change probability
147	    const slider = screen.getByRole("slider");
148	    fireEvent.change(slider, { target: { value: "0.3" } });
149	
150	    // Submit
151	    const button = screen.getByRole("button", { name: "Submit Edit" });
152	    fireEvent.click(button);
153	
154	    expect(mockMutate).toHaveBeenCalledTimes(1);
155	    const call = mockMutate.mock.calls[0]![0];
156	    expect(call.payload.accountId).toBe("acc-123");
157	    expect(call.payload.variableId).toBe("var-1");
158	    expect(call.payload.target).toEqual({
159	      kind: "marginal",
160	      outcomeId: "out-no",
161	      probability: 0.3,
162	    });
163	    expect(call.payload.idempotencyKey).toBeDefined();
164	    expect(call.session).toEqual({ accountId: "acc-123", agentId: "agent-1" });
165	  });
166	
167	  it("disables submit button and shows Submitting text when mutation is pending", () => {
168	    mockUseProbabilityEdit.mockReturnValue(
169	      defaultMutationState({ isPending: true, isIdle: false, status: "pending" }),
170	    );
